mapper.select:
SELECT MTF.ID, MTF.ITEM_CD, MFI.ITEM_NM, MTF.TRADE_TYPE, MTF.SHIP_LENGTH, MTF.SHIP_TYPE_CODE, MDD_SHIP_TYPE.DICT_LABEL SHIP_TYPE_LABEL, MTF.RATE, MTF.TAX_RATE, MTF.CREATE_BY, MTF.CREATE_BY_NAME, MTF.CREATE_TIME, MTF.UPDATE_BY, MTF.UPDATE_BY_NAME, MTF.UPDATE_TIME FROM M_TUG_FEE MTF JOIN M_FEE_ITEM MFI ON MTF.ITEM_CD = MFI.ITEM_CD JOIN M_DICT_DATA MDD_SHIP_TYPE ON ( MDD_SHIP_TYPE.DICT_TYPE = 'SHIP_TYPE' AND MTF.SHIP_TYPE_CODE = MDD_SHIP_TYPE.DICT_VALUE )
AND TRADE_TYPE = #{tradeType, jdbcType=VARCHAR}
AND SHIP_TYPE_CODE = #{shipTypeCode, jdbcType=VARCHAR}

mapper.delete:
DELETE
FROM M_TUG_FEE
WHERE ID = #{id, jdbcType=BIGINT}
